import{_ as a,o as t,c as i,ag as o}from"./chunks/framework.BZohXCq9.js";const h=JSON.parse('{"title":"MailYou","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1773655718000}'),l={name:"guide/index.md"};function r(s,e,d,n,c,u){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="mailyou" tabindex="-1">MailYou <a class="header-anchor" href="#mailyou" aria-label="Permalink to &quot;MailYou&quot;">​</a></h1><p>MailYou is a local-first desktop mail client built for a calmer daily workflow.</p><h2 id="built-for-desktop-workflows" tabindex="-1">Built for desktop workflows <a class="header-anchor" href="#built-for-desktop-workflows" aria-label="Permalink to &quot;Built for desktop workflows&quot;">​</a></h2><p>MailYou uses Vue for the interface, Electron for desktop integration, and Rust for mail access and local persistence. The goal is simple: keep the app comfortable to use while keeping mail data close to the device.</p><h2 id="account-setup" tabindex="-1">Account setup <a class="header-anchor" href="#account-setup" aria-label="Permalink to &quot;Account setup&quot;">​</a></h2><p>MailYou tries to keep setup short:</p><ul><li>It starts from the email address.</li><li>It picks a provider preset when the domain is known.</li><li>It only shows OAuth when that provider actually supports OAuth.</li><li>It keeps server details hidden unless preset data is missing or advanced mode is enabled.</li></ul><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><p>MailYou supports two OAuth paths:</p><ul><li>Direct provider OAuth with local <code>client_id</code> and <code>client_secret</code></li><li>MailYou OAuth proxy with a built-in default URL and desktop token</li></ul><p>For providers without OAuth, MailYou falls back to standard password-based setup.</p><h2 id="privacy-direction" tabindex="-1">Privacy direction <a class="header-anchor" href="#privacy-direction" aria-label="Permalink to &quot;Privacy direction&quot;">​</a></h2><p>MailYou is designed around local desktop storage. It does not position itself as a hosted mailbox or cloud sync service.</p><p>Legal documents are published on this website:</p><ul><li><a href="/legal/privacy-policy.html">Privacy Policy</a></li><li><a href="/legal/terms-of-service.html">Terms of Service</a></li></ul>',15)])])}const f=a(l,[["render",r]]);export{h as __pageData,f as default};
